+  function handleDragEnter(e: DragEvent): void {
+    if (!hasFiles(e.dataTransfer)) return;
+    e.preventDefault();
+    dragCounter++;
+    isDragging = true;
+  }
+
+  function handleDragOver(e: DragEvent): void {
+    if (!hasFiles(e.dataTransfer)) return;
+    e.preventDefault();
+    if (e.dataTransfer) e.dataTransfer.dropEffect = 'copy';
+  }
+
+  function handleDragLeave(_e: DragEvent): void {
+    dragCounter--;
+    if (dragCounter <= 0) {
+      dragCounter = 0;
+      isDragging = false;
+    }
+  }
+
+  function handleDrop(e: DragEvent): void {
+    e.preventDefault();
+    dragCounter = 0;
+    isDragging = false;
+    if (!e.dataTransfer) return;
+    // Extract files synchronously — DataTransferItemList becomes invalid after handler returns
+    const files: File[] = [];
+    for (let i = 0; i < e.dataTransfer.items.length; i++) {
+      const item = e.dataTransfer.items[i];
+      if (item.kind === 'file') {
+        const file = item.getAsFile();
+        if (file) files.push(file);
+      }
+    }
+    if (files.length > 0) onFileDrop?.(files);
+  }
+
+  function handlePaste(e: ClipboardEvent): void {
+    if (!e.clipboardData) return;
+    // Check items for file-kind entries (images, copied files)
+    const files: File[] = [];
+    for (let i = 0; i < e.clipboardData.items.length; i++) {
+      const item = e.clipboardData.items[i];
+      if (item.kind === 'file') {
+        const file = item.getAsFile();
+        if (file) files.push(file);
+      }
+    }
+    if (files.length > 0) {
+      e.preventDefault();
+      onFileDrop?.(files);
+      return;
+    }
+    // No files — handle as text paste into terminal
+    const text = e.clipboardData.getData('text/plain');
+    if (text) {
+      e.preventDefault();
+      onTextPaste?.(text);
+    }
+  }
